#!/bin/bash\n\nDEPLOYMENTS_FILE=\"/data/.openclaw/workspace/publish-website-traefik/deployments.json\"\n\nif [ ! -f \"$DEPLOYMENTS_FILE\" ]; then\n    echo \"No deployments found.\"\n    exit 0\nfi\n\necho \"--- Deployed Websites ---\"\njq -r 'to_entries[] | \"Subdomain: \\(.key)\\n  URL: \\(.value.url)\\n  Temp Dir: \\(.value.temp_dir)\\n  Container: \\(.value.container_name)\\n\"' \"$DEPLOYMENTS_FILE\"\necho \"-------------------------\\"\n